"use client";

import { Checkbox as CheckboxPrimitive } from "@base-ui/react/checkbox";
import { CheckboxGroup as CheckboxGroupPrimitive } from "@base-ui/react/checkbox-group";
import * as stylex from "@stylexjs/stylex";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { checkboxStyles } from "./checkbox.styles";

type CheckboxGroupProps = PropsWithStylex<CheckboxGroupPrimitive.Props>;


type CheckboxProps = PropsWithStylex<CheckboxPrimitive.Root.Props>;

export function CheckboxGroup({ style, ...props }: CheckboxGroupProps) {
	return (
		<CheckboxGroupPrimitive
			{...stylex.props(checkboxStyles.group, style)}
			{...props}
		/>
	);
}

export function Checkbox({ style, ...props }: CheckboxProps) {
	return (
		<CheckboxPrimitive.Root
			{...props}
			render={(rootProps, { disabled }) => (
				<span
					{...rootProps}
					{...stylex.props(
						checkboxStyles.root,
						disabled && checkboxStyles.rootDisabled,
						style,
					)}
					data-slot="checkbox"
				>
					<CheckboxPrimitive.Indicator
						render={(_indicatorProps, state) => (
							<span
								{...stylex.props(
									checkboxStyles.indicator,
									!state.indeterminate && checkboxStyles.indicatorChecked,
									state.indeterminate && checkboxStyles.indicatorIndeterminate,
								)}
								data-slot="checkbox-indicator"
							>
								{state.indeterminate ? (
									<svg
										aria-hidden="true"
										{...stylex.props(checkboxStyles.icon)}
										fill="none"
										height="24"
										stroke="currentColor"
										strokeLinecap="round"
										strokeLinejoin="round"
										strokeWidth="3"
										viewBox="0 0 24 24"
										width="24"
										xmlns="http://www.w3.org/2000/svg"
									>
										<path d="M5.252 12h13.496" />
									</svg>
								) : (
									<svg
										aria-hidden="true"
										{...stylex.props(checkboxStyles.icon)}
										fill="none"
										height="24"
										stroke="currentColor"
										strokeLinecap="round"
										strokeLinejoin="round"
										strokeWidth="3"
										viewBox="0 0 24 24"
										width="24"
										xmlns="http://www.w3.org/2000/svg"
									>
										<path d="M5.252 12.7 10.2 18.63 18.748 5.37" />
									</svg>
								)}
							</span>
						)}
					/>
				</span>
			)}
		/>
	);
}

export { CheckboxPrimitive, CheckboxGroupPrimitive };

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import {
	borderRadius,
	borderWidth,
	mediaQueries,
	spacing,
} from "@/lib/theme/tokens.stylex";

export const checkboxStyles = stylex.create({
	root: {
		position: "relative",
		display: "inline-flex",
		alignItems: "center",
		justifyContent: "center",
		flexShrink: 0,
		width: {
			default: 18,
			[mediaQueries.sm]: 16,
		},
		height: {
			default: 18,
			[mediaQueries.sm]: 16,
		},
		borderRadius: borderRadius.small,
		borderWidth: borderWidth.thin,
		borderStyle: "solid",
		borderColor: theme.border,
		backgroundColor: theme.background,
		outline: "none",
		transitionProperty: "box-shadow",
		transitionDuration: "150ms",
		":focus-visible": {
			boxShadow: `0 0 0 2px ${theme.focusRing}`,
		},
		// "&[aria-invalid]": {
		// 	borderColor: theme.sentimentNegative,
		// },
	},
	rootDisabled: {
		cursor: "not-allowed",
		opacity: 0.64,
	},
	group: {
		display: "flex",
		flexDirection: "column",
		alignItems: "flex-start",
		gap: spacing.small,
	},
	indicator: {
		position: "absolute",
		top: -1,
		left: -1,
		right: -1,
		bottom: -1,
		display: "flex",
		alignItems: "center",
		justifyContent: "center",
		borderRadius: borderRadius.small,
		color: theme.contentOnPrimary,
	},
	indicatorChecked: {
		backgroundColor: theme.primary,
		color: theme.contentOnPrimary,
	},
	indicatorIndeterminate: {
		color: theme.contentPrimary,
	},
	icon: {
		width: {
			default: 14,
			[mediaQueries.sm]: 12,
		},
		height: {
			default: 14,
			[mediaQueries.sm]: 12,
		},
	},
});
